/// Compute squared L2 distance between two 128-dim f32 vectors.
/// Returns f64 for compatibility with SearchResult.distance.
/// Uses AVX-512 when available (target-cpu=native in release build).
#[inline(always)]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());
    l2_distance_f32(a, b) as f64
}

#[inline(always)]
pub fn l2_distance_f32(a: &[f32], b: &[f32]) -> f32 {
    // With target-cpu=native and opt-level=3, the compiler will auto-vectorize
    // this into AVX-512 instructions on Cascade Lake.
    let mut sum = 0.0f32;
    let len = a.len().min(b.len());
    // Unroll manually to help auto-vectorization
    let chunks = len / 16;
    let remainder = len % 16;
    let mut i = 0usize;

    // Process 16 floats at a time (one AVX-512 register)
    for _ in 0..chunks {
        let d0 = a[i] - b[i];
        let d1 = a[i+1] - b[i+1];
        let d2 = a[i+2] - b[i+2];
        let d3 = a[i+3] - b[i+3];
        let d4 = a[i+4] - b[i+4];
        let d5 = a[i+5] - b[i+5];
        let d6 = a[i+6] - b[i+6];
        let d7 = a[i+7] - b[i+7];
        let d8 = a[i+8] - b[i+8];
        let d9 = a[i+9] - b[i+9];
        let d10 = a[i+10] - b[i+10];
        let d11 = a[i+11] - b[i+11];
        let d12 = a[i+12] - b[i+12];
        let d13 = a[i+13] - b[i+13];
        let d14 = a[i+14] - b[i+14];
        let d15 = a[i+15] - b[i+15];
        sum += d0*d0 + d1*d1 + d2*d2 + d3*d3
             + d4*d4 + d5*d5 + d6*d6 + d7*d7
             + d8*d8 + d9*d9 + d10*d10 + d11*d11
             + d12*d12 + d13*d13 + d14*d14 + d15*d15;
        i += 16;
    }

    // Remainder
    for j in 0..remainder {
        let d = a[i+j] - b[i+j];
        sum += d * d;
    }
    sum
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, Ordering};

const DIM: usize = 128;
const NUM_CENTROIDS: usize = 1024;      // IVF cells
const PROBE: usize = 32;               // number of cells to probe at query time
const MAX_VECTORS: usize = 1_100_000;  // pre-allocate

/// Flat contiguous storage of all vectors: [id, v0, v1, ..., v127] per vector
/// We store vectors in a flat Vec<f32> for cache efficiency.
/// vectors_flat: capacity MAX_VECTORS * (1 + DIM), but we use parallel arrays:
///   - ids: Vec<u64>
///   - data: Vec<f32> stored as DIM floats per vector, row-major

pub struct VectorDB {
    /// RwLock protecting all mutable state
    inner: RwLock<Inner>,
    /// Whether the IVF index is built
    index_ready: AtomicBool,
}

struct Inner {
    /// Flat vector storage: entry i occupies data[i*DIM .. (i+1)*DIM]
    data: Vec<f32>,
    /// Vector IDs, parallel to data
    ids: Vec<u64>,
    /// IVF index (built once after bulk_insert)
    ivf: Option<IvfIndex>,
}

struct IvfIndex {
    /// Centroids: NUM_CENTROIDS * DIM floats, row-major
    centroids: Vec<f32>,
    /// For each centroid c, the list of vector indices assigned to it
    cells: Vec<Vec<u32>>,
}

impl IvfIndex {
    /// Get centroid slice c
    #[inline(always)]
    fn centroid(&self, c: usize) -> &[f32] {
        &self.centroids[c * DIM..(c + 1) * DIM]
    }
}

impl VectorDB {
    pub fn new() -> Self {
        let inner = Inner {
            data: Vec::with_capacity(MAX_VECTORS * DIM),
            ids: Vec::with_capacity(MAX_VECTORS),
            ivf: None,
        };
        VectorDB {
            inner: RwLock::new(inner),
            index_ready: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write();
        let v = if vector.len() == DIM {
            vector
        } else {
            let mut v = vector;
            v.resize(DIM, 0.0);
            v
        };
        inner.data.extend_from_slice(&v);
        inner.ids.push(id);
        // Invalidate index
        inner.ivf = None;
        self.index_ready.store(false, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        {
            let mut inner = self.inner.write();
            inner.data.reserve(count * DIM);
            inner.ids.reserve(count);
            for (id, vector) in &vectors {
                if vector.len() == DIM {
                    inner.data.extend_from_slice(vector);
                } else {
                    inner.data.extend_from_slice(vector);
                    // pad if needed
                    let pad = DIM.saturating_sub(vector.len());
                    for _ in 0..pad {
                        inner.data.push(0.0);
                    }
                }
                inner.ids.push(*id);
            }
            // Invalidate index
            inner.ivf = None;
            self.index_ready.store(false, Ordering::Relaxed);
        }

        // Build index after bulk insert
        self.build_index();
        count
    }

    fn build_index(&self) {
        // Run k-means to build IVF index
        let (n, centroids_flat) = {
            let inner = self.inner.read();
            let n = inner.ids.len();
            if n < NUM_CENTROIDS {
                return;
            }
            // Sample initial centroids (evenly spaced)
            let step = n / NUM_CENTROIDS;
            let mut centroids = Vec::with_capacity(NUM_CENTROIDS * DIM);
            for c in 0..NUM_CENTROIDS {
                let idx = c * step;
                centroids.extend_from_slice(&inner.data[idx * DIM..(idx + 1) * DIM]);
            }
            (n, centroids)
        };

        // K-means iterations (run on a read-locked view)
        let iters = 20;
        let mut centroids = centroids_flat;
        let mut assignments: Vec<u32> = vec![0u32; n];

        for _iter in 0..iters {
            let changed = {
                let inner = self.inner.read();
                // Assign each vector to nearest centroid (parallel)
                let new_assignments: Vec<u32> = (0..n)
                    .into_par_iter()
                    .map(|i| {
                        let v = &inner.data[i * DIM..(i + 1) * DIM];
                        nearest_centroid(&centroids, v) as u32
                    })
                    .collect();
                let changed = new_assignments != assignments;
                assignments = new_assignments;
                changed
            };

            if !changed {
                break;
            }

            // Recompute centroids
            let mut sums = vec![0.0f32; NUM_CENTROIDS * DIM];
            let mut counts = vec![0u32; NUM_CENTROIDS];

            {
                let inner = self.inner.read();
                for i in 0..n {
                    let c = assignments[i] as usize;
                    let v = &inner.data[i * DIM..(i + 1) * DIM];
                    let cs = &mut sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM {
                        cs[d] += v[d];
                    }
                    counts[c] += 1;
                }
            }

            for c in 0..NUM_CENTROIDS {
                let cnt = counts[c];
                if cnt > 0 {
                    let cf = cnt as f32;
                    let cs = &mut centroids[c * DIM..(c + 1) * DIM];
                    let ss = &sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM {
                        cs[d] = ss[d] / cf;
                    }
                }
            }
        }

        // Build cells: assign each vector to its centroid
        let mut cells: Vec<Vec<u32>> = vec![Vec::new(); NUM_CENTROIDS];
        for i in 0..n {
            let c = assignments[i] as usize;
            cells[c].push(i as u32);
        }

        // Store in inner
        {
            let mut inner = self.inner.write();
            inner.ivf = Some(IvfIndex { centroids, cells });
        }
        self.index_ready.store(true, Ordering::Release);
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let inner = self.inner.read();
        let n = inner.ids.len();
        if n == 0 {
            return vec![];
        }

        let top_k = top_k as usize;

        if let Some(ref ivf) = inner.ivf {
            // IVF search: find nearest PROBE centroids, then search those cells
            let probe = PROBE.min(NUM_CENTROIDS);

            // Find nearest centroids
            let mut centroid_dists: Vec<(f32, usize)> = (0..NUM_CENTROIDS)
                .map(|c| {
                    let dist = l2_distance_f32(vector, ivf.centroid(c));
                    (dist, c)
                })
                .collect();

            // Partial sort to get top PROBE
            centroid_dists.select_nth_unstable_by(probe - 1, |a, b| {
                a.0.partial_cmp(&b.0).unwrap()
            });
            centroid_dists.truncate(probe);

            // Collect candidate indices from probed cells
            let total_candidates: usize = centroid_dists.iter()
                .map(|(_, c)| ivf.cells[*c].len())
                .sum();

            let mut results: Vec<(f32, u64)> = Vec::with_capacity(total_candidates);

            for (_, c) in &centroid_dists {
                let cell = &ivf.cells[*c];
                for &vi in cell {
                    let vi = vi as usize;
                    let v = &inner.data[vi * DIM..(vi + 1) * DIM];
                    let dist = l2_distance_f32(vector, v);
                    results.push((dist, inner.ids[vi]));
                }
            }

            // Partial sort to get top_k
            if results.len() > top_k {
                results.select_nth_unstable_by(top_k - 1, |a, b| {
                    a.0.partial_cmp(&b.0).unwrap()
                });
                results.truncate(top_k);
            }
            results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

            results
                .into_iter()
                .map(|(dist, id)| SearchResult {
                    id,
                    distance: dist as f64,
                })
                .collect()
        } else {
            // Brute force fallback (parallel)
            let data = &inner.data;
            let ids = &inner.ids;

            let mut results: Vec<(f32, u64)> = (0..n)
                .into_par_iter()
                .map(|i| {
                    let v = &data[i * DIM..(i + 1) * DIM];
                    let dist = l2_distance_f32(vector, v);
                    (dist, ids[i])
                })
                .collect();

            if results.len() > top_k {
                results.select_nth_unstable_by(top_k - 1, |a, b| {
                    a.0.partial_cmp(&b.0).unwrap()
                });
                results.truncate(top_k);
            }
            results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

            results
                .into_iter()
                .map(|(dist, id)| SearchResult {
                    id,
                    distance: dist as f64,
                })
                .collect()
        }
    }
}

/// Find the index of the nearest centroid to vector v.
#[inline]
fn nearest_centroid(centroids: &[f32], v: &[f32]) -> usize {
    let mut best_dist = f32::MAX;
    let mut best_idx = 0usize;
    for c in 0..NUM_CENTROIDS {
        let cent = &centroids[c * DIM..(c + 1) * DIM];
        let dist = l2_distance_f32(v, cent);
        if dist < best_dist {
            best_dist = dist;
            best_idx = c;
        }
    }
    best_idx
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, Ordering};

const DIM: usize = 128;
const NUM_CENTROIDS: usize = 2048;   // IVF cells
const PROBE: usize = 48;             // cells to probe at query time
const KMEANS_ITERS: usize = 12;

pub struct VectorDB {
    inner: RwLock<Inner>,
    index_ready: AtomicBool,
}

struct Inner {
    /// Flat vector storage: entry i occupies data[i*DIM .. (i+1)*DIM]
    data: Vec<f32>,
    /// Vector IDs, parallel to data
    ids: Vec<u64>,
    /// IVF index (built after bulk_insert)
    ivf: Option<IvfIndex>,
}

struct IvfIndex {
    /// Centroids: NUM_CENTROIDS * DIM floats, row-major
    centroids: Vec<f32>,
    /// For each centroid, the list of vector indices in that cell
    cells: Vec<Vec<u32>>,
}

impl IvfIndex {
    #[inline(always)]
    fn centroid(&self, c: usize) -> &[f32] {
        &self.centroids[c * DIM..(c + 1) * DIM]
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Inner {
                data: Vec::new(),
                ids: Vec::new(),
                ivf: None,
            }),
            index_ready: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write();
        push_vector(&mut inner.data, &vector);
        inner.ids.push(id);
        inner.ivf = None;
        self.index_ready.store(false, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        {
            let mut inner = self.inner.write();
            inner.data.reserve(count * DIM);
            inner.ids.reserve(count);
            for (id, v) in &vectors {
                push_vector(&mut inner.data, v);
                inner.ids.push(*id);
            }
            inner.ivf = None;
        }
        // Build IVF index (parallel k-means)
        self.build_index();
        count
    }

    fn build_index(&self) {
        let n = {
            let inner = self.inner.read();
            inner.ids.len()
        };
        if n < NUM_CENTROIDS {
            return;
        }

        // Sample initial centroids (evenly spaced)
        let mut centroids: Vec<f32> = {
            let inner = self.inner.read();
            let step = n / NUM_CENTROIDS;
            let mut c = Vec::with_capacity(NUM_CENTROIDS * DIM);
            for ci in 0..NUM_CENTROIDS {
                let idx = ci * step;
                c.extend_from_slice(&inner.data[idx * DIM..(idx + 1) * DIM]);
            }
            c
        };

        let mut assignments: Vec<u32> = vec![0u32; n];

        for _iter in 0..KMEANS_ITERS {
            // --- Assignment step (parallel) ---
            let new_assignments: Vec<u32> = {
                let inner = self.inner.read();
                (0..n)
                    .into_par_iter()
                    .map(|i| {
                        let v = &inner.data[i * DIM..(i + 1) * DIM];
                        nearest_centroid_idx(&centroids, v) as u32
                    })
                    .collect()
            };

            let changed = new_assignments != assignments;
            assignments = new_assignments;
            if !changed {
                break;
            }

            // --- Update step (parallel per centroid) ---
            // First gather sums and counts in parallel chunks
            let nthreads = 4usize;
            let chunk_size = (n + nthreads - 1) / nthreads;

            let partial: Vec<(Vec<f32>, Vec<u32>)> = (0..nthreads)
                .into_par_iter()
                .map(|t| {
                    let start = t * chunk_size;
                    let end = (start + chunk_size).min(n);
                    let mut sums = vec![0.0f32; NUM_CENTROIDS * DIM];
                    let mut counts = vec![0u32; NUM_CENTROIDS];
                    let inner = self.inner.read();
                    for i in start..end {
                        let c = assignments[i] as usize;
                        let v = &inner.data[i * DIM..(i + 1) * DIM];
                        let cs = &mut sums[c * DIM..(c + 1) * DIM];
                        for d in 0..DIM {
                            cs[d] += v[d];
                        }
                        counts[c] += 1;
                    }
                    (sums, counts)
                })
                .collect();

            // Merge partial results
            let mut sums = vec![0.0f32; NUM_CENTROIDS * DIM];
            let mut counts = vec![0u32; NUM_CENTROIDS];
            for (s, c) in partial {
                for i in 0..NUM_CENTROIDS * DIM {
                    sums[i] += s[i];
                }
                for i in 0..NUM_CENTROIDS {
                    counts[i] += c[i];
                }
            }

            // Divide to get new centroids
            for c in 0..NUM_CENTROIDS {
                if counts[c] > 0 {
                    let cf = counts[c] as f32;
                    let cs = &mut centroids[c * DIM..(c + 1) * DIM];
                    let ss = &sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM {
                        cs[d] = ss[d] / cf;
                    }
                }
            }
        }

        // Build cell lists
        let mut cells: Vec<Vec<u32>> = {
            // Pre-size each cell
            let mut cell_counts = vec![0u32; NUM_CENTROIDS];
            for &a in &assignments {
                cell_counts[a as usize] += 1;
            }
            let mut c: Vec<Vec<u32>> = cell_counts
                .iter()
                .map(|&cnt| Vec::with_capacity(cnt as usize))
                .collect();
            for (i, &a) in assignments.iter().enumerate() {
                c[a as usize].push(i as u32);
            }
            c
        };

        // Sort each cell by index for cache-friendly access
        for cell in &mut cells {
            cell.sort_unstable();
        }

        {
            let mut inner = self.inner.write();
            inner.ivf = Some(IvfIndex { centroids, cells });
        }
        self.index_ready.store(true, Ordering::Release);
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let inner = self.inner.read();
        let n = inner.ids.len();
        if n == 0 {
            return vec![];
        }

        let top_k = top_k as usize;

        if let Some(ref ivf) = inner.ivf {
            let probe = PROBE.min(NUM_CENTROIDS);

            // Find nearest centroids (can be done in parallel but 2048 centroids is cheap)
            let mut centroid_dists: Vec<(f32, usize)> = (0..NUM_CENTROIDS)
                .map(|c| {
                    let dist = l2_distance_f32(vector, ivf.centroid(c));
                    (dist, c)
                })
                .collect();

            centroid_dists.select_nth_unstable_by(probe - 1, |a, b| {
                a.0.partial_cmp(&b.0).unwrap()
            });
            centroid_dists.truncate(probe);

            // Collect candidate results
            let data = &inner.data;
            let ids = &inner.ids;

            // Build candidate list
            let total: usize = centroid_dists.iter().map(|(_, c)| ivf.cells[*c].len()).sum();
            let mut results: Vec<(f32, u64)> = Vec::with_capacity(total);

            for (_, c) in &centroid_dists {
                for &vi in &ivf.cells[*c] {
                    let vi = vi as usize;
                    let v = &data[vi * DIM..(vi + 1) * DIM];
                    let dist = l2_distance_f32(vector, v);
                    results.push((dist, ids[vi]));
                }
            }

            // Partial sort for top_k
            if results.len() > top_k {
                results.select_nth_unstable_by(top_k - 1, |a, b| {
                    a.0.partial_cmp(&b.0).unwrap()
                });
                results.truncate(top_k);
            }
            results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

            results
                .into_iter()
                .map(|(dist, id)| SearchResult { id, distance: dist as f64 })
                .collect()
        } else {
            // Brute force fallback
            let data = &inner.data;
            let ids = &inner.ids;

            let mut results: Vec<(f32, u64)> = (0..n)
                .into_par_iter()
                .map(|i| {
                    let dist = l2_distance_f32(vector, &data[i * DIM..(i + 1) * DIM]);
                    (dist, ids[i])
                })
                .collect();

            if results.len() > top_k {
                results.select_nth_unstable_by(top_k - 1, |a, b| {
                    a.0.partial_cmp(&b.0).unwrap()
                });
                results.truncate(top_k);
            }
            results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

            results
                .into_iter()
                .map(|(dist, id)| SearchResult { id, distance: dist as f64 })
                .collect()
        }
    }
}

#[inline(always)]
fn push_vector(data: &mut Vec<f32>, v: &[f32]) {
    if v.len() >= DIM {
        data.extend_from_slice(&v[..DIM]);
    } else {
        data.extend_from_slice(v);
        for _ in v.len()..DIM {
            data.push(0.0);
        }
    }
}

#[inline(always)]
fn nearest_centroid_idx(centroids: &[f32], v: &[f32]) -> usize {
    let mut best_dist = f32::MAX;
    let mut best_idx = 0usize;
    for c in 0..NUM_CENTROIDS {
        let cent = &centroids[c * DIM..(c + 1) * DIM];
        let dist = l2_distance_f32(v, cent);
        if dist < best_dist {
            best_dist = dist;
            best_idx = c;
        }
    }
    best_idx
}

/// Compute squared L2 distance between two f32 vectors.
/// With target-cpu=native (Cascade Lake) the compiler will emit AVX-512 code.
#[inline(always)]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    l2_distance_f32(a, b) as f64
}

#[inline(always)]
pub fn l2_distance_f32(a: &[f32], b: &[f32]) -> f32 {
    // Manual 16-wide unroll matches one AVX-512 register width.
    // The Rust compiler with opt-level=3 and target-cpu=native will auto-vectorize
    // this into vmovups/vsubps/vfmadd231ps patterns on Cascade Lake.
    let len = a.len().min(b.len());
    let mut sum0 = 0.0f32;
    let mut sum1 = 0.0f32;
    let mut sum2 = 0.0f32;
    let mut sum3 = 0.0f32;

    let chunks = len / 16;
    let mut i = 0usize;

    for _ in 0..chunks {
        let d0  = a[i]    - b[i];
        let d1  = a[i+1]  - b[i+1];
        let d2  = a[i+2]  - b[i+2];
        let d3  = a[i+3]  - b[i+3];
        let d4  = a[i+4]  - b[i+4];
        let d5  = a[i+5]  - b[i+5];
        let d6  = a[i+6]  - b[i+6];
        let d7  = a[i+7]  - b[i+7];
        let d8  = a[i+8]  - b[i+8];
        let d9  = a[i+9]  - b[i+9];
        let d10 = a[i+10] - b[i+10];
        let d11 = a[i+11] - b[i+11];
        let d12 = a[i+12] - b[i+12];
        let d13 = a[i+13] - b[i+13];
        let d14 = a[i+14] - b[i+14];
        let d15 = a[i+15] - b[i+15];
        sum0 += d0*d0 + d1*d1 + d2*d2 + d3*d3;
        sum1 += d4*d4 + d5*d5 + d6*d6 + d7*d7;
        sum2 += d8*d8 + d9*d9 + d10*d10 + d11*d11;
        sum3 += d12*d12 + d13*d13 + d14*d14 + d15*d15;
        i += 16;
    }

    let mut sum = sum0 + sum1 + sum2 + sum3;
    for j in i..len {
        let d = a[j] - b[j];
        sum += d * d;
    }
    sum
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, Ordering};

const DIM: usize = 128;
const NUM_CENTROIDS: usize = 2048;   // IVF cells
const PROBE: usize = 48;             // cells to probe at query time
const KMEANS_ITERS: usize = 15;

pub struct VectorDB {
    inner: RwLock<Inner>,
    index_ready: AtomicBool,
}

struct Inner {
    /// Flat vector storage: entry i occupies data[i*DIM .. (i+1)*DIM]
    data: Vec<f32>,
    /// Vector IDs, parallel to data
    ids: Vec<u64>,
    /// IVF index (built after bulk_insert)
    ivf: Option<IvfIndex>,
}

struct IvfIndex {
    /// Centroids: NUM_CENTROIDS * DIM floats, row-major
    centroids: Vec<f32>,
    /// For each centroid, the list of vector indices in that cell
    cells: Vec<Vec<u32>>,
}

impl IvfIndex {
    #[inline(always)]
    fn centroid(&self, c: usize) -> &[f32] {
        &self.centroids[c * DIM..(c + 1) * DIM]
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Inner {
                data: Vec::new(),
                ids: Vec::new(),
                ivf: None,
            }),
            index_ready: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write();
        push_vector(&mut inner.data, &vector);
        inner.ids.push(id);
        inner.ivf = None;
        self.index_ready.store(false, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        {
            let mut inner = self.inner.write();
            inner.data.reserve(count * DIM);
            inner.ids.reserve(count);
            for (id, v) in &vectors {
                push_vector(&mut inner.data, v);
                inner.ids.push(*id);
            }
            inner.ivf = None;
        }
        // Build IVF index
        self.build_index();
        count
    }

    fn build_index(&self) {
        // Copy data out so we don't hold the lock during heavy computation
        let (data_snapshot, n) = {
            let inner = self.inner.read();
            let n = inner.ids.len();
            (inner.data.clone(), n)
        };

        if n < NUM_CENTROIDS {
            return;
        }

        // Sample initial centroids (evenly spaced)
        let step = n / NUM_CENTROIDS;
        let mut centroids: Vec<f32> = Vec::with_capacity(NUM_CENTROIDS * DIM);
        for ci in 0..NUM_CENTROIDS {
            let idx = ci * step;
            centroids.extend_from_slice(&data_snapshot[idx * DIM..(idx + 1) * DIM]);
        }

        let mut assignments: Vec<u32> = vec![0u32; n];

        for _iter in 0..KMEANS_ITERS {
            // --- Assignment step (parallel) ---
            let new_assignments: Vec<u32> = (0..n)
                .into_par_iter()
                .map(|i| {
                    let v = &data_snapshot[i * DIM..(i + 1) * DIM];
                    nearest_centroid_idx(&centroids, v) as u32
                })
                .collect();

            let changed = new_assignments != assignments;
            assignments = new_assignments;
            if !changed {
                break;
            }

            // --- Update step ---
            // Parallel partial sums
            let nthreads = 4usize;
            let chunk_size = (n + nthreads - 1) / nthreads;

            let partial: Vec<(Vec<f32>, Vec<u32>)> = (0..nthreads)
                .into_par_iter()
                .map(|t| {
                    let start = t * chunk_size;
                    let end = (start + chunk_size).min(n);
                    let mut sums = vec![0.0f32; NUM_CENTROIDS * DIM];
                    let mut counts = vec![0u32; NUM_CENTROIDS];
                    for i in start..end {
                        let c = assignments[i] as usize;
                        let v = &data_snapshot[i * DIM..(i + 1) * DIM];
                        let cs = &mut sums[c * DIM..(c + 1) * DIM];
                        for d in 0..DIM {
                            cs[d] += v[d];
                        }
                        counts[c] += 1;
                    }
                    (sums, counts)
                })
                .collect();

            let mut sums = vec![0.0f32; NUM_CENTROIDS * DIM];
            let mut counts = vec![0u32; NUM_CENTROIDS];
            for (s, c) in &partial {
                for i in 0..NUM_CENTROIDS * DIM {
                    sums[i] += s[i];
                }
                for i in 0..NUM_CENTROIDS {
                    counts[i] += c[i];
                }
            }

            for c in 0..NUM_CENTROIDS {
                if counts[c] > 0 {
                    let cf = counts[c] as f32;
                    let cs = &mut centroids[c * DIM..(c + 1) * DIM];
                    let ss = &sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM {
                        cs[d] = ss[d] / cf;
                    }
                }
            }
        }

        // Build cell lists with known capacities
        let mut cell_counts = vec![0u32; NUM_CENTROIDS];
        for &a in &assignments {
            cell_counts[a as usize] += 1;
        }
        let mut cells: Vec<Vec<u32>> = cell_counts
            .iter()
            .map(|&cnt| Vec::with_capacity(cnt as usize))
            .collect();
        for (i, &a) in assignments.iter().enumerate() {
            cells[a as usize].push(i as u32);
        }

        {
            let mut inner = self.inner.write();
            inner.ivf = Some(IvfIndex { centroids, cells });
        }
        self.index_ready.store(true, Ordering::Release);
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let inner = self.inner.read();
        let n = inner.ids.len();
        if n == 0 {
            return vec![];
        }

        let top_k = top_k as usize;

        if let Some(ref ivf) = inner.ivf {
            let probe = PROBE.min(NUM_CENTROIDS);
            let data = &inner.data;
            let ids = &inner.ids;

            // Find nearest centroids
            let mut centroid_dists: Vec<(f32, usize)> = (0..NUM_CENTROIDS)
                .map(|c| (l2_distance_f32(vector, ivf.centroid(c)), c))
                .collect();

            centroid_dists.select_nth_unstable_by(probe - 1, |a, b| {
                a.0.partial_cmp(&b.0).unwrap()
            });
            centroid_dists.truncate(probe);

            // Scan candidate vectors
            let total: usize = centroid_dists.iter().map(|(_, c)| ivf.cells[*c].len()).sum();
            let mut results: Vec<(f32, u64)> = Vec::with_capacity(total);

            for (_, c) in &centroid_dists {
                for &vi in &ivf.cells[*c] {
                    let vi = vi as usize;
                    let dist = l2_distance_f32(vector, &data[vi * DIM..(vi + 1) * DIM]);
                    results.push((dist, ids[vi]));
                }
            }

            if results.len() > top_k {
                results.select_nth_unstable_by(top_k - 1, |a, b| {
                    a.0.partial_cmp(&b.0).unwrap()
                });
                results.truncate(top_k);
            }
            results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

            results
                .into_iter()
                .map(|(dist, id)| SearchResult { id, distance: dist as f64 })
                .collect()
        } else {
            // Brute force fallback
            let data = &inner.data;
            let ids = &inner.ids;

            let mut results: Vec<(f32, u64)> = (0..n)
                .into_par_iter()
                .map(|i| {
                    let dist = l2_distance_f32(vector, &data[i * DIM..(i + 1) * DIM]);
                    (dist, ids[i])
                })
                .collect();

            if results.len() > top_k {
                results.select_nth_unstable_by(top_k - 1, |a, b| {
                    a.0.partial_cmp(&b.0).unwrap()
                });
                results.truncate(top_k);
            }
            results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());

            results
                .into_iter()
                .map(|(dist, id)| SearchResult { id, distance: dist as f64 })
                .collect()
        }
    }
}

#[inline(always)]
fn push_vector(data: &mut Vec<f32>, v: &[f32]) {
    if v.len() >= DIM {
        data.extend_from_slice(&v[..DIM]);
    } else {
        data.extend_from_slice(v);
        for _ in v.len()..DIM {
            data.push(0.0);
        }
    }
}

#[inline(always)]
fn nearest_centroid_idx(centroids: &[f32], v: &[f32]) -> usize {
    let mut best_dist = f32::MAX;
    let mut best_idx = 0usize;
    for c in 0..NUM_CENTROIDS {
        let cent = &centroids[c * DIM..(c + 1) * DIM];
        let dist = l2_distance_f32(v, cent);
        if dist < best_dist {
            best_dist = dist;
            best_idx = c;
        }
    }
    best_idx
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, Ordering};

const DIM: usize = 128;
const NUM_CENTROIDS: usize = 1024;   // IVF cells — fewer = faster build
const PROBE: usize = 32;             // cells to probe at query time
const KMEANS_ITERS: usize = 10;

pub struct VectorDB {
    inner: RwLock<Inner>,
    index_ready: AtomicBool,
}

struct Inner {
    data: Vec<f32>,  // flat: entry i at [i*DIM..(i+1)*DIM]
    ids: Vec<u64>,
    ivf: Option<IvfIndex>,
}

struct IvfIndex {
    centroids: Vec<f32>,  // NUM_CENTROIDS * DIM
    cells: Vec<Vec<u32>>, // cell -> list of vector indices
}

impl IvfIndex {
    #[inline(always)]
    fn centroid(&self, c: usize) -> &[f32] {
        &self.centroids[c * DIM..(c + 1) * DIM]
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Inner {
                data: Vec::new(),
                ids: Vec::new(),
                ivf: None,
            }),
            index_ready: AtomicBool::new(false),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write();
        push_vector(&mut inner.data, &vector);
        inner.ids.push(id);
        inner.ivf = None;
        self.index_ready.store(false, Ordering::Relaxed);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        {
            let mut inner = self.inner.write();
            inner.data.reserve(count * DIM);
            inner.ids.reserve(count);
            for (id, v) in &vectors {
                push_vector(&mut inner.data, v);
                inner.ids.push(*id);
            }
            inner.ivf = None;
        }
        self.build_index();
        count
    }

    fn build_index(&self) {
        // Snapshot data (clone) so we don't hold the lock during heavy computation
        let (data_snap, n) = {
            let inner = self.inner.read();
            let n = inner.ids.len();
            (inner.data.clone(), n)
        };

        if n < NUM_CENTROIDS {
            return;
        }

        // Use a random subsample for k-means to speed up building
        // Sample at most 200_000 vectors for centroid computation
        let sample_size = 200_000usize.min(n);
        let step = n / sample_size;

        // Initial centroids: evenly-spaced from sample
        let init_step = sample_size / NUM_CENTROIDS;
        let mut centroids: Vec<f32> = Vec::with_capacity(NUM_CENTROIDS * DIM);
        for ci in 0..NUM_CENTROIDS {
            let sample_idx = ci * init_step;
            let data_idx = sample_idx * step;
            centroids.extend_from_slice(&data_snap[data_idx * DIM..(data_idx + 1) * DIM]);
        }

        // Build sample indices
        let sample_indices: Vec<usize> = (0..sample_size).map(|s| s * step).collect();
        let sample_n = sample_indices.len();

        let mut assignments: Vec<u32> = vec![0u32; sample_n];

        // K-means on the sample
        for _iter in 0..KMEANS_ITERS {
            // Assignment
            let new_asgn: Vec<u32> = sample_indices
                .par_iter()
                .map(|&si| {
                    let v = &data_snap[si * DIM..(si + 1) * DIM];
                    nearest_centroid_idx(&centroids, v) as u32
                })
                .collect();

            if new_asgn == assignments {
                break;
            }
            assignments = new_asgn;

            // Update centroids (parallel reduction)
            let nc = NUM_CENTROIDS;
            let nthreads = 4usize;
            let chunk = (sample_n + nthreads - 1) / nthreads;

            let partials: Vec<(Vec<f32>, Vec<u32>)> = (0..nthreads)
                .into_par_iter()
                .map(|t| {
                    let start = t * chunk;
                    let end = (start + chunk).min(sample_n);
                    let mut sums = vec![0.0f32; nc * DIM];
                    let mut cnts = vec![0u32; nc];
                    for i in start..end {
                        let c = assignments[i] as usize;
                        let v = &data_snap[sample_indices[i] * DIM..(sample_indices[i] + 1) * DIM];
                        let s = &mut sums[c * DIM..(c + 1) * DIM];
                        for d in 0..DIM {
                            s[d] += v[d];
                        }
                        cnts[c] += 1;
                    }
                    (sums, cnts)
                })
                .collect();

            let mut total_sums = vec![0.0f32; nc * DIM];
            let mut total_cnts = vec![0u32; nc];
            for (s, c) in &partials {
                for i in 0..nc * DIM { total_sums[i] += s[i]; }
                for i in 0..nc      { total_cnts[i] += c[i]; }
            }
            for c in 0..nc {
                if total_cnts[c] > 0 {
                    let cf = total_cnts[c] as f32;
                    let cs = &mut centroids[c * DIM..(c + 1) * DIM];
                    let ss = &total_sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM { cs[d] = ss[d] / cf; }
                }
            }
        }

        // Now assign ALL n vectors to nearest centroid
        let all_assignments: Vec<u32> = (0..n)
            .into_par_iter()
            .map(|i| {
                let v = &data_snap[i * DIM..(i + 1) * DIM];
                nearest_centroid_idx(&centroids, v) as u32
            })
            .collect();

        // Build cell lists
        let mut cell_counts = vec![0u32; NUM_CENTROIDS];
        for &a in &all_assignments {
            cell_counts[a as usize] += 1;
        }
        let mut cells: Vec<Vec<u32>> = cell_counts
            .iter()
            .map(|&cnt| Vec::with_capacity(cnt as usize))
            .collect();
        for (i, &a) in all_assignments.iter().enumerate() {
            cells[a as usize].push(i as u32);
        }

        {
            let mut inner = self.inner.write();
            inner.ivf = Some(IvfIndex { centroids, cells });
        }
        self.index_ready.store(true, Ordering::Release);
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let inner = self.inner.read();
        let n = inner.ids.len();
        if n == 0 {
            return vec![];
        }

        let top_k = top_k as usize;

        if let Some(ref ivf) = inner.ivf {
            let probe = PROBE.min(NUM_CENTROIDS);
            let data = &inner.data;
            let ids = &inner.ids;

            // Find nearest probe centroids
            let mut cdists: Vec<(f32, usize)> = (0..NUM_CENTROIDS)
                .map(|c| (l2_distance_f32(vector, ivf.centroid(c)), c))
                .collect();
            cdists.select_nth_unstable_by(probe - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
            cdists.truncate(probe);

            // Scan candidate vectors
            let total: usize = cdists.iter().map(|(_, c)| ivf.cells[*c].len()).sum();
            let mut results: Vec<(f32, u64)> = Vec::with_capacity(total);
            for (_, c) in &cdists {
                for &vi in &ivf.cells[*c] {
                    let vi = vi as usize;
                    let dist = l2_distance_f32(vector, &data[vi * DIM..(vi + 1) * DIM]);
                    results.push((dist, ids[vi]));
                }
            }

            if results.len() > top_k {
                results.select_nth_unstable_by(top_k - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
                results.truncate(top_k);
            }
            results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
            results.into_iter().map(|(d, id)| SearchResult { id, distance: d as f64 }).collect()
        } else {
            // Brute force
            let data = &inner.data;
            let ids = &inner.ids;
            let mut results: Vec<(f32, u64)> = (0..n)
                .into_par_iter()
                .map(|i| (l2_distance_f32(vector, &data[i * DIM..(i + 1) * DIM]), ids[i]))
                .collect();
            if results.len() > top_k {
                results.select_nth_unstable_by(top_k - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
                results.truncate(top_k);
            }
            results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
            results.into_iter().map(|(d, id)| SearchResult { id, distance: d as f64 }).collect()
        }
    }
}

#[inline(always)]
fn push_vector(data: &mut Vec<f32>, v: &[f32]) {
    if v.len() >= DIM {
        data.extend_from_slice(&v[..DIM]);
    } else {
        data.extend_from_slice(v);
        for _ in v.len()..DIM { data.push(0.0); }
    }
}

#[inline(always)]
fn nearest_centroid_idx(centroids: &[f32], v: &[f32]) -> usize {
    let mut best = f32::MAX;
    let mut best_idx = 0usize;
    for c in 0..NUM_CENTROIDS {
        let d = l2_distance_f32(v, &centroids[c * DIM..(c + 1) * DIM]);
        if d < best { best = d; best_idx = c; }
    }
    best_idx
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;
use std::sync::atomic::{AtomicBool, Ordering};

const DIM: usize = 128;
const NUM_CENTROIDS: usize = 4096;   // IVF cells
const PROBE: usize = 64;             // cells to probe at query time
const KMEANS_ITERS: usize = 20;
const KMEANS_SAMPLE: usize = 100_000; // vectors to use for k-means training

pub struct VectorDB {
    inner: RwLock<Inner>,
    index_ready: AtomicBool,
