    assignments: &[u32],
    nc: usize,
    sample_n: usize,
) -> (Vec<f32>, Vec<u32>) {
    let nthreads = 4usize;
    let chunk = (sample_n + nthreads - 1) / nthreads;

    let partials: Vec<(Vec<f32>, Vec<u32>)> = (0..nthreads)
        .into_par_iter()
        .map(|t| {
            let start = t * chunk;
            let end = (start + chunk).min(sample_n);
            let mut sums = vec![0.0f32; nc * DIM];
            let mut cnts = vec![0u32; nc];
            for i in start..end {
                let c = assignments[i] as usize;
                let v = &sample_data[i * DIM..(i + 1) * DIM];
                let s = &mut sums[c * DIM..(c + 1) * DIM];
                for d in 0..DIM { s[d] += v[d]; }
                cnts[c] += 1;
            }
            (sums, cnts)
        })
        .collect();

    let mut total_sums = vec![0.0f32; nc * DIM];
    let mut total_cnts = vec![0u32; nc];
    for (s, c) in &partials {
        for i in 0..nc * DIM { total_sums[i] += s[i]; }
        for i in 0..nc { total_cnts[i] += c[i]; }
    }
    (total_sums, total_cnts)
}

#[inline(always)]
fn push_vector(data: &mut Vec<f32>, v: &[f32]) {
    if v.len() >= DIM {
        data.extend_from_slice(&v[..DIM]);
    } else {
        data.extend_from_slice(v);
        for _ in v.len()..DIM { data.push(0.0); }
    }
}

#[inline(always)]
fn nearest_centroid_idx(centroids: &[f32], v: &[f32]) -> usize {
    let mut best = f32::MAX;
    let mut best_idx = 0usize;
    for c in 0..NUM_CENTROIDS {
        let d = l2_distance_f32(v, &centroids[c * DIM..(c + 1) * DIM]);
        if d < best { best = d; best_idx = c; }
    }
    best_idx
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;

const DIM: usize = 128;
const NUM_CENTROIDS: usize = 1024;
const PROBE: usize = 32;
const KMEANS_ITERS: usize = 15;
// Number of vectors to subsample for k-means training
const KMEANS_SAMPLE: usize = 50_000;

pub struct VectorDB {
    /// All state under one RwLock. Build index while holding write lock is OK
    /// since bulk_insert is called once; queries come after.
    inner: RwLock<Inner>,
}

struct Inner {
    data: Vec<f32>,       // row-major: vector i at [i*DIM..(i+1)*DIM]
    ids: Vec<u64>,
    ivf: Option<IvfIndex>,
}

struct IvfIndex {
    centroids: Vec<f32>,  // NUM_CENTROIDS * DIM
    cells: Vec<Vec<u32>>, // cell -> sorted indices into data/ids
}

impl IvfIndex {
    #[inline(always)]
    fn centroid(&self, c: usize) -> &[f32] {
        &self.centroids[c * DIM..(c + 1) * DIM]
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Inner {
                data: Vec::new(),
                ids: Vec::new(),
                ivf: None,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write();
        push_vector(&mut inner.data, &vector);
        inner.ids.push(id);
        inner.ivf = None;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut inner = self.inner.write();
        inner.data.reserve(count * DIM);
        inner.ids.reserve(count);
        for (id, v) in &vectors {
            push_vector(&mut inner.data, v);
            inner.ids.push(*id);
        }

        // Build index while holding write lock (no readers during load phase)
        build_ivf_index(&mut inner, count);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let inner = self.inner.read();
        let n = inner.ids.len();
        if n == 0 { return vec![]; }
        let top_k = top_k as usize;

        if let Some(ref ivf) = inner.ivf {
            search_ivf(&inner, ivf, vector, top_k)
        } else {
            search_brute(&inner, vector, top_k)
        }
    }
}

/// Build IVF index in-place inside Inner (data and ids already populated).
fn build_ivf_index(inner: &mut Inner, _inserted: usize) {
    let n = inner.ids.len();
    let nc = NUM_CENTROIDS;

    if n < nc {
        inner.ivf = None;
        return;
    }

    let data = &inner.data;

    // ---- Step 1: Gather a contiguous sample for faster k-means ----
    let sample_n = KMEANS_SAMPLE.min(n);
    let sample_step = n / sample_n;

    let mut sample_data: Vec<f32> = Vec::with_capacity(sample_n * DIM);
    for i in 0..sample_n {
        let di = i * sample_step;
        sample_data.extend_from_slice(&data[di * DIM..(di + 1) * DIM]);
    }

    // ---- Step 2: K-means++ style init (just take evenly spaced) ----
    let init_step = sample_n / nc;
    let mut centroids: Vec<f32> = Vec::with_capacity(nc * DIM);
    for ci in 0..nc {
        let si = ci * init_step;
        centroids.extend_from_slice(&sample_data[si * DIM..(si + 1) * DIM]);
    }

    let mut sample_asgn = vec![0u32; sample_n];

    // ---- Step 3: K-means iterations on the sample ----
    for _iter in 0..KMEANS_ITERS {
        // Assign each sample to nearest centroid (parallel)
        let new_asgn: Vec<u32> = (0..sample_n)
            .into_par_iter()
            .map(|i| nearest_centroid_idx(&centroids, &sample_data[i * DIM..(i + 1) * DIM]) as u32)
            .collect();

        if new_asgn == sample_asgn { break; }
        sample_asgn = new_asgn;

        // Update centroids via parallel reduction
        let nthreads = 4usize;
        let chunk = (sample_n + nthreads - 1) / nthreads;

        let partials: Vec<(Vec<f32>, Vec<u32>)> = (0..nthreads)
            .into_par_iter()
            .map(|t| {
                let start = t * chunk;
                let end = (start + chunk).min(sample_n);
                let mut sums = vec![0.0f32; nc * DIM];
                let mut cnts = vec![0u32; nc];
                for i in start..end {
                    let c = sample_asgn[i] as usize;
                    let v = &sample_data[i * DIM..(i + 1) * DIM];
                    let s = &mut sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM { s[d] += v[d]; }
                    cnts[c] += 1;
                }
                (sums, cnts)
            })
            .collect();

        let mut tsums = vec![0.0f32; nc * DIM];
        let mut tcnts = vec![0u32; nc];
        for (s, c) in &partials {
            for i in 0..nc * DIM { tsums[i] += s[i]; }
            for i in 0..nc { tcnts[i] += c[i]; }
        }
        for c in 0..nc {
            if tcnts[c] > 0 {
                let cf = tcnts[c] as f32;
                let cs = &mut centroids[c * DIM..(c + 1) * DIM];
                let ss = &tsums[c * DIM..(c + 1) * DIM];
                for d in 0..DIM { cs[d] = ss[d] / cf; }
            }
        }
    }
    drop(sample_data);

    // ---- Step 4: Assign all n vectors to their nearest centroid (parallel) ----
    let all_asgn: Vec<u32> = (0..n)
        .into_par_iter()
        .map(|i| nearest_centroid_idx(&centroids, &data[i * DIM..(i + 1) * DIM]) as u32)
        .collect();

    // ---- Step 5: Build cells ----
    let mut cell_counts = vec![0u32; nc];
    for &a in &all_asgn { cell_counts[a as usize] += 1; }
    let mut cells: Vec<Vec<u32>> = cell_counts
        .iter()
        .map(|&cnt| Vec::with_capacity(cnt as usize))
        .collect();
    for (i, &a) in all_asgn.iter().enumerate() {
        cells[a as usize].push(i as u32);
    }

    inner.ivf = Some(IvfIndex { centroids, cells });
}

fn search_ivf(inner: &Inner, ivf: &IvfIndex, vector: &[f32], top_k: usize) -> Vec<SearchResult> {
    let probe = PROBE.min(NUM_CENTROIDS);
    let data = &inner.data;
    let ids = &inner.ids;

    // Find nearest probe centroids
    let mut cdists: Vec<(f32, usize)> = (0..NUM_CENTROIDS)
        .map(|c| (l2_distance_f32(vector, ivf.centroid(c)), c))
        .collect();
    cdists.select_nth_unstable_by(probe - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
    cdists.truncate(probe);

    let total: usize = cdists.iter().map(|(_, c)| ivf.cells[*c].len()).sum();
    let mut results: Vec<(f32, u64)> = Vec::with_capacity(total);
    for (_, c) in &cdists {
        for &vi in &ivf.cells[*c] {
            let vi = vi as usize;
            let dist = l2_distance_f32(vector, &data[vi * DIM..(vi + 1) * DIM]);
            results.push((dist, ids[vi]));
        }
    }

    if results.len() > top_k {
        results.select_nth_unstable_by(top_k - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
        results.truncate(top_k);
    }
    results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
    results.into_iter().map(|(d, id)| SearchResult { id, distance: d as f64 }).collect()
}

fn search_brute(inner: &Inner, vector: &[f32], top_k: usize) -> Vec<SearchResult> {
    let n = inner.ids.len();
    let data = &inner.data;
    let ids = &inner.ids;
    let mut results: Vec<(f32, u64)> = (0..n)
        .into_par_iter()
        .map(|i| (l2_distance_f32(vector, &data[i * DIM..(i + 1) * DIM]), ids[i]))
        .collect();
    if results.len() > top_k {
        results.select_nth_unstable_by(top_k - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
        results.truncate(top_k);
    }
    results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
    results.into_iter().map(|(d, id)| SearchResult { id, distance: d as f64 }).collect()
}

#[inline(always)]
fn push_vector(data: &mut Vec<f32>, v: &[f32]) {
    if v.len() >= DIM {
        data.extend_from_slice(&v[..DIM]);
    } else {
        data.extend_from_slice(v);
        for _ in v.len()..DIM { data.push(0.0); }
    }
}

#[inline(always)]
fn nearest_centroid_idx(centroids: &[f32], v: &[f32]) -> usize {
    let mut best = f32::MAX;
    let mut best_idx = 0usize;
    for c in 0..NUM_CENTROIDS {
        let d = l2_distance_f32(v, &centroids[c * DIM..(c + 1) * DIM]);
        if d < best { best = d; best_idx = c; }
    }
    best_idx
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::RwLock;
use rayon::prelude::*;

const DIM: usize = 128;

// IVF parameters:
//   - NUM_CENTROIDS: number of Voronoi cells
//   - PROBE: how many cells to examine at query time (recall vs. speed tradeoff)
//   - KMEANS_ITERS: k-means iterations (few is fine with good init)
//   - KMEANS_SAMPLE: subsample size for centroid training
//
// For 1M vectors with 4 cores and ~512MB data:
//   sqrt(1M) = 1000 → use 1024 cells.
//   Average cell size = 1000 vectors.
//   Probing 32 cells = examining ~32K vectors per query → fast.
const NUM_CENTROIDS: usize = 1024;
const PROBE: usize = 32;
const KMEANS_ITERS: usize = 8;
const KMEANS_SAMPLE: usize = 50_000;

pub struct VectorDB {
    inner: RwLock<Inner>,
}

struct Inner {
    data: Vec<f32>,       // row-major: vector i at [i*DIM..(i+1)*DIM]
    ids: Vec<u64>,
    ivf: Option<IvfIndex>,
}

struct IvfIndex {
    centroids: Vec<f32>,  // NUM_CENTROIDS * DIM
    cells: Vec<Vec<u32>>,
}

impl IvfIndex {
    #[inline(always)]
    fn centroid(&self, c: usize) -> &[f32] {
        &self.centroids[c * DIM..(c + 1) * DIM]
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Inner {
                data: Vec::new(),
                ids: Vec::new(),
                ivf: None,
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write();
        push_vector(&mut inner.data, &vector);
        inner.ids.push(id);
        inner.ivf = None;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();
        let mut inner = self.inner.write();
        inner.data.reserve(count * DIM);
        inner.ids.reserve(count);
        for (id, v) in &vectors {
            push_vector(&mut inner.data, v);
            inner.ids.push(*id);
        }
        build_ivf_index(&mut inner);
        count
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let inner = self.inner.read();
        let n = inner.ids.len();
        if n == 0 { return vec![]; }
        let top_k = top_k as usize;

        if let Some(ref ivf) = inner.ivf {
            search_ivf(&inner, ivf, vector, top_k)
        } else {
            search_brute(&inner, vector, top_k)
        }
    }
}

fn build_ivf_index(inner: &mut Inner) {
    let n = inner.ids.len();
    let nc = NUM_CENTROIDS;

    if n < nc * 4 {
        inner.ivf = None;
        return;
    }

    let data = &inner.data;

    // ── Step 1: gather contiguous sample ──
    let sample_n = KMEANS_SAMPLE.min(n);
    let sample_step = (n / sample_n).max(1);

    let mut sample_data: Vec<f32> = Vec::with_capacity(sample_n * DIM);
    for i in 0..sample_n {
        let di = (i * sample_step).min(n - 1);
        sample_data.extend_from_slice(&data[di * DIM..(di + 1) * DIM]);
    }

    // ── Step 2: initial centroids (evenly spaced from sample) ──
    let init_step = (sample_n / nc).max(1);
    let mut centroids: Vec<f32> = Vec::with_capacity(nc * DIM);
    for ci in 0..nc {
        let si = (ci * init_step).min(sample_n - 1);
        centroids.extend_from_slice(&sample_data[si * DIM..(si + 1) * DIM]);
    }

    let mut sample_asgn = vec![0u32; sample_n];

    // ── Step 3: K-means on the sample ──
    for _iter in 0..KMEANS_ITERS {
        // Parallel assignment
        let new_asgn: Vec<u32> = (0..sample_n)
            .into_par_iter()
            .map(|i| nearest_centroid(&centroids, &sample_data[i * DIM..(i + 1) * DIM]) as u32)
            .collect();

        if new_asgn == sample_asgn { break; }
        sample_asgn = new_asgn;

        // Parallel centroid update (4-thread reduction)
        let (tsums, tcnts) = reduce_centroids(&sample_data, &sample_asgn, nc, sample_n);
        for c in 0..nc {
            if tcnts[c] > 0 {
                let cf = tcnts[c] as f32;
                let cs = &mut centroids[c * DIM..(c + 1) * DIM];
                let ss = &tsums[c * DIM..(c + 1) * DIM];
                for d in 0..DIM { cs[d] = ss[d] / cf; }
            }
        }
    }
    drop(sample_data);

    // ── Step 4: assign ALL vectors to nearest centroid ──
    let all_asgn: Vec<u32> = (0..n)
        .into_par_iter()
        .map(|i| nearest_centroid(&centroids, &data[i * DIM..(i + 1) * DIM]) as u32)
        .collect();

    // ── Step 5: build cell lists ──
    let mut cell_counts = vec![0u32; nc];
    for &a in &all_asgn { cell_counts[a as usize] += 1; }
    let mut cells: Vec<Vec<u32>> = cell_counts
        .iter()
        .map(|&cnt| Vec::with_capacity(cnt as usize))
        .collect();
    for (i, &a) in all_asgn.iter().enumerate() {
        cells[a as usize].push(i as u32);
    }

    inner.ivf = Some(IvfIndex { centroids, cells });
}

fn reduce_centroids(
    sample_data: &[f32],
    asgn: &[u32],
    nc: usize,
    sample_n: usize,
) -> (Vec<f32>, Vec<u32>) {
    let nthreads = 4usize;
    let chunk = (sample_n + nthreads - 1) / nthreads;

    let partials: Vec<(Vec<f32>, Vec<u32>)> = (0..nthreads)
        .into_par_iter()
        .map(|t| {
            let start = t * chunk;
            let end = (start + chunk).min(sample_n);
            let mut sums = vec![0.0f32; nc * DIM];
            let mut cnts = vec![0u32; nc];
            for i in start..end {
                let c = asgn[i] as usize;
                let v = &sample_data[i * DIM..(i + 1) * DIM];
                let s = &mut sums[c * DIM..(c + 1) * DIM];
                for d in 0..DIM { s[d] += v[d]; }
                cnts[c] += 1;
            }
            (sums, cnts)
        })
        .collect();

    let mut tsums = vec![0.0f32; nc * DIM];
    let mut tcnts = vec![0u32; nc];
    for (s, c) in &partials {
        for i in 0..nc * DIM { tsums[i] += s[i]; }
        for i in 0..nc { tcnts[i] += c[i]; }
    }
    (tsums, tcnts)
}

fn search_ivf(inner: &Inner, ivf: &IvfIndex, vector: &[f32], top_k: usize) -> Vec<SearchResult> {
    let probe = PROBE.min(NUM_CENTROIDS);
    let data = &inner.data;
    let ids = &inner.ids;

    // Find nearest probe centroids
    let mut cdists: Vec<(f32, usize)> = (0..NUM_CENTROIDS)
        .map(|c| (l2_distance_f32(vector, ivf.centroid(c)), c))
        .collect();
    cdists.select_nth_unstable_by(probe - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
    cdists.truncate(probe);

    let total: usize = cdists.iter().map(|(_, c)| ivf.cells[*c].len()).sum();
    let mut results: Vec<(f32, u64)> = Vec::with_capacity(total);
    for (_, c) in &cdists {
        for &vi in &ivf.cells[*c] {
            let vi = vi as usize;
            let dist = l2_distance_f32(vector, &data[vi * DIM..(vi + 1) * DIM]);
            results.push((dist, ids[vi]));
        }
    }

    if results.len() > top_k {
        results.select_nth_unstable_by(top_k - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
        results.truncate(top_k);
    }
    results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
    results.into_iter().map(|(d, id)| SearchResult { id, distance: d as f64 }).collect()
}

fn search_brute(inner: &Inner, vector: &[f32], top_k: usize) -> Vec<SearchResult> {
    let n = inner.ids.len();
    let data = &inner.data;
    let ids = &inner.ids;
    let mut results: Vec<(f32, u64)> = (0..n)
        .into_par_iter()
        .map(|i| (l2_distance_f32(vector, &data[i * DIM..(i + 1) * DIM]), ids[i]))
        .collect();
    if results.len() > top_k {
        results.select_nth_unstable_by(top_k - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
        results.truncate(top_k);
    }
    results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
    results.into_iter().map(|(d, id)| SearchResult { id, distance: d as f64 }).collect()
}

#[inline(always)]
fn push_vector(data: &mut Vec<f32>, v: &[f32]) {
    if v.len() >= DIM {
        data.extend_from_slice(&v[..DIM]);
    } else {
        data.extend_from_slice(v);
        for _ in v.len()..DIM { data.push(0.0); }
    }
}

#[inline(always)]
fn nearest_centroid(centroids: &[f32], v: &[f32]) -> usize {
    let mut best = f32::MAX;
    let mut best_idx = 0usize;
    for c in 0..NUM_CENTROIDS {
        let d = l2_distance_f32(v, &centroids[c * DIM..(c + 1) * DIM]);
        if d < best { best = d; best_idx = c; }
    }
    best_idx
}

