use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::{Condvar, Mutex, RwLock};
use rayon::prelude::*;

const DIM: usize = 128;
const NUM_CENTROIDS: usize = 1024;
const PROBE: usize = 32;
const KMEANS_ITERS: usize = 5;
const KMEANS_SAMPLE: usize = 50_000;

pub struct VectorDB {
    inner: RwLock<Inner>,
    /// Signals when the IVF index has been built
    index_ready: Mutex<bool>,
    index_cv: Condvar,
}

struct Inner {
    data: Vec<f32>,
    ids: Vec<u64>,
    ivf: Option<IvfIndex>,
}

struct IvfIndex {
    centroids: Vec<f32>,
    cells: Vec<Vec<u32>>,
}

impl IvfIndex {
    #[inline(always)]
    fn centroid(&self, c: usize) -> &[f32] {
        &self.centroids[c * DIM..(c + 1) * DIM]
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Inner {
                data: Vec::new(),
                ids: Vec::new(),
                ivf: None,
            }),
            index_ready: Mutex::new(false),
            index_cv: Condvar::new(),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write();
        push_vector(&mut inner.data, &vector);
        inner.ids.push(id);
        inner.ivf = None;
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();

        // Insert all vectors (holding write lock only for the insert phase)
        {
            let mut inner = self.inner.write();
            inner.data.reserve(count * DIM);
            inner.ids.reserve(count);
            for (id, v) in &vectors {
                push_vector(&mut inner.data, v);
                inner.ids.push(*id);
            }
            inner.ivf = None;
        }

        // Build the IVF index. We do this on the current thread but must
        // NOT block the tokio async runtime. Since this is called from an
        // async handler (tokio), we use rayon to do the heavy lifting on a
        // separate thread pool while we block the current thread for a very
        // short time. The actual response is only sent after bulk_insert returns.
        //
        // The key insight: tokio's handle_bulk_insert is an async fn that
        // awaits nothing — it calls db.bulk_insert() synchronously. As long
        // as we return from bulk_insert in a timely manner, the response will
        // be sent. K-means on 50K vectors for 5 iterations should take ~2-5s
        // which is acceptable.
        self.build_index_sync();
        count
    }

    fn build_index_sync(&self) {
        // Snapshot just the data slice we need (clone is O(n) but done once)
        let (data_snap, n) = {
            let inner = self.inner.read();
            (inner.data.clone(), inner.ids.len())
        };

        let nc = NUM_CENTROIDS;
        if n < nc * 4 { return; }

        // Build sample
        let sample_n = KMEANS_SAMPLE.min(n);
        let sample_step = n / sample_n;
        let mut sample_data: Vec<f32> = Vec::with_capacity(sample_n * DIM);
        for i in 0..sample_n {
            let di = i * sample_step;
            sample_data.extend_from_slice(&data_snap[di * DIM..(di + 1) * DIM]);
        }

        // Init centroids
        let init_step = sample_n / nc;
        let mut centroids: Vec<f32> = Vec::with_capacity(nc * DIM);
        for ci in 0..nc {
            let si = ci * init_step;
            centroids.extend_from_slice(&sample_data[si * DIM..(si + 1) * DIM]);
        }

        // K-means iterations
        let mut sample_asgn = vec![0u32; sample_n];
        for _iter in 0..KMEANS_ITERS {
            let new_asgn: Vec<u32> = (0..sample_n)
                .into_par_iter()
                .map(|i| nearest_centroid(&centroids, &sample_data[i * DIM..(i + 1) * DIM]) as u32)
                .collect();
            if new_asgn == sample_asgn { break; }
            sample_asgn = new_asgn;

            let mut sums = vec![0.0f32; nc * DIM];
            let mut cnts = vec![0u32; nc];
            for i in 0..sample_n {
                let c = sample_asgn[i] as usize;
                let v = &sample_data[i * DIM..(i + 1) * DIM];
                let s = &mut sums[c * DIM..(c + 1) * DIM];
                for d in 0..DIM { s[d] += v[d]; }
                cnts[c] += 1;
            }
            for c in 0..nc {
                if cnts[c] > 0 {
                    let cf = cnts[c] as f32;
                    let cs = &mut centroids[c * DIM..(c + 1) * DIM];
                    let ss = &sums[c * DIM..(c + 1) * DIM];
                    for d in 0..DIM { cs[d] = ss[d] / cf; }
                }
            }
        }
        drop(sample_data);

        // Assign ALL vectors
        let all_asgn: Vec<u32> = (0..n)
            .into_par_iter()
            .map(|i| nearest_centroid(&centroids, &data_snap[i * DIM..(i + 1) * DIM]) as u32)
            .collect();
        drop(data_snap);

        // Build cells
        let mut cell_counts = vec![0u32; nc];
        for &a in &all_asgn { cell_counts[a as usize] += 1; }
        let mut cells: Vec<Vec<u32>> = cell_counts
            .iter()
            .map(|&cnt| Vec::with_capacity(cnt as usize))
            .collect();
        for (i, &a) in all_asgn.iter().enumerate() {
            cells[a as usize].push(i as u32);
        }

        let mut inner = self.inner.write();
        if inner.ids.len() == n {
            inner.ivf = Some(IvfIndex { centroids, cells });
        }
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let inner = self.inner.read();
        let n = inner.ids.len();
        if n == 0 { return vec![]; }
        let top_k = top_k as usize;

        if let Some(ref ivf) = inner.ivf {
            search_ivf(&inner, ivf, vector, top_k)
        } else {
            search_brute(&inner, vector, top_k)
        }
    }
}

fn search_ivf(inner: &Inner, ivf: &IvfIndex, vector: &[f32], top_k: usize) -> Vec<SearchResult> {
    let probe = PROBE.min(NUM_CENTROIDS);
    let data = &inner.data;
    let ids = &inner.ids;

    let mut cdists: Vec<(f32, usize)> = (0..NUM_CENTROIDS)
        .map(|c| (l2_distance_f32(vector, ivf.centroid(c)), c))
        .collect();
    cdists.select_nth_unstable_by(probe - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
    cdists.truncate(probe);

    let total: usize = cdists.iter().map(|(_, c)| ivf.cells[*c].len()).sum();
    let mut results: Vec<(f32, u64)> = Vec::with_capacity(total);
    for (_, c) in &cdists {
        for &vi in &ivf.cells[*c] {
            let vi = vi as usize;
            let dist = l2_distance_f32(vector, &data[vi * DIM..(vi + 1) * DIM]);
            results.push((dist, ids[vi]));
        }
    }

    if results.len() > top_k {
        results.select_nth_unstable_by(top_k - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
        results.truncate(top_k);
    }
    results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
    results.into_iter().map(|(d, id)| SearchResult { id, distance: d as f64 }).collect()
}

fn search_brute(inner: &Inner, vector: &[f32], top_k: usize) -> Vec<SearchResult> {
    let n = inner.ids.len();
    let data = &inner.data;
    let ids = &inner.ids;
    let mut results: Vec<(f32, u64)> = (0..n)
        .into_par_iter()
        .map(|i| (l2_distance_f32(vector, &data[i * DIM..(i + 1) * DIM]), ids[i]))
        .collect();
    if results.len() > top_k {
        results.select_nth_unstable_by(top_k - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
        results.truncate(top_k);
    }
    results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
    results.into_iter().map(|(d, id)| SearchResult { id, distance: d as f64 }).collect()
}

#[inline(always)]
fn push_vector(data: &mut Vec<f32>, v: &[f32]) {
    if v.len() >= DIM {
        data.extend_from_slice(&v[..DIM]);
    } else {
        data.extend_from_slice(v);
        for _ in v.len()..DIM { data.push(0.0); }
    }
}

#[inline(always)]
fn nearest_centroid(centroids: &[f32], v: &[f32]) -> usize {
    let mut best = f32::MAX;
    let mut best_idx = 0usize;
    for c in 0..NUM_CENTROIDS {
        let d = l2_distance_f32(v, &centroids[c * DIM..(c + 1) * DIM]);
        if d < best { best = d; best_idx = c; }
    }
    best_idx
}

use crate::api::SearchResult;
use crate::distance::l2_distance_f32;
use parking_lot::{Condvar, Mutex, RwLock};
use rayon::prelude::*;

const DIM: usize = 128;
const NUM_CENTROIDS: usize = 1024;
const PROBE: usize = 32;
const KMEANS_ITERS: usize = 5;
const KMEANS_SAMPLE: usize = 50_000;

/// The shared state structure.
///
/// Key design: `bulk_insert` stores data quickly and returns.
/// Then it spawns a Rayon task to build the IVF index in the background.
/// `search` waits if the index is being built (via Condvar), or falls back
/// to brute force if no index has been requested yet.
pub struct VectorDB {
    inner: RwLock<Inner>,
    /// Used to wait for index completion
    building: Mutex<bool>,
    build_done: Condvar,
}

struct Inner {
    data: Vec<f32>,
    ids: Vec<u64>,
    ivf: Option<IvfIndex>,
}

struct IvfIndex {
    centroids: Vec<f32>,
    cells: Vec<Vec<u32>>,
}

impl IvfIndex {
    #[inline(always)]
    fn centroid(&self, c: usize) -> &[f32] {
        &self.centroids[c * DIM..(c + 1) * DIM]
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            inner: RwLock::new(Inner {
                data: Vec::new(),
                ids: Vec::new(),
                ivf: None,
            }),
            building: Mutex::new(false),
            build_done: Condvar::new(),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write();
        push_vector(&mut inner.data, &vector);
        inner.ids.push(id);
        inner.ivf = None;
    }

    /// Insert all vectors and build the IVF index.
    /// This runs the heavy index-building work on the Rayon thread pool (blocking
    /// rayon threads, not tokio threads).  The function returns only after the
    /// index is fully built so the HTTP server can start serving queries
    /// immediately after responding to the bulk_insert request.
    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();

        // Phase 1: insert data (hold write lock only for the insert)
        {
            let mut inner = self.inner.write();
            inner.data.reserve(count * DIM);
            inner.ids.reserve(count);
            for (id, v) in &vectors {
                push_vector(&mut inner.data, v);
                inner.ids.push(*id);
            }
            inner.ivf = None;
        }

        // Phase 2: build IVF index.
        // We run the index build on a dedicated std::thread so we don't block
        // the tokio async runtime thread.  We wait synchronously so that the
        // HTTP response is sent only after the index is ready.
        //
        // This is safe because the HTTP handler calls this in a
        // `tokio::task::spawn_blocking` context implicitly via axum's
        // Json extractor (actually it doesn't — axum handlers are async).
        //
        // Since we cannot modify main.rs, and the handler is an async fn that
        // calls db.bulk_insert() synchronously, we need build_index_sync to
        // complete quickly OR return to the caller and build in the background
        // while search falls back to brute force.
        //
        // Strategy: build in background, return count immediately.
        // Search will use brute force until the index is ready.
        self.build_index_background();
        count
    }

    fn build_index_background(&self) {
        // Mark as building
        {
            let mut b = self.building.lock();
            *b = true;
        }

        // Snapshot data
        let (data_snap, n) = {
            let inner = self.inner.read();
            (inner.data.clone(), inner.ids.len())
        };

        // We can't capture self (not 'static) in a new thread directly.
        // Instead, build synchronously but using rayon's thread pool.
        // Rayon operations won't block the tokio runtime (they use their own threads).
        //
        // Actually the issue is that bulk_insert is called from the tokio task
        // directly (the async fn just awaits Json extraction then calls db.bulk_insert).
        // Heavy work here stalls the tokio thread pool.
        //
        // Since we can't modify main.rs, and bulk_insert must return (to generate
        // the HTTP response), we use a std::thread for the background work.
        // We store a raw pointer to self which is safe because:
        // 1. VectorDB lives for the lifetime of the server (Arc<VectorDB>)
        // 2. We signal completion via build_done condvar

        let ptr = self as *const VectorDB;

        // SAFETY: VectorDB is inside an Arc, so it outlives this thread.
        // The thread holds no references across the spawn—it uses the raw pointer
        // only to write the completed index.
        let _ = std::thread::spawn(move || {
            // SAFETY: ptr is valid for the server lifetime
            let db: &VectorDB = unsafe { &*ptr };

            let nc = NUM_CENTROIDS;
            if n >= nc * 4 {
                let ivf = build_ivf(data_snap, n, nc);

                let mut inner = db.inner.write();
                if inner.ids.len() == n {
                    inner.ivf = Some(ivf);
                }
            }

            // Signal done
            let mut b = db.building.lock();
            *b = false;
            db.build_done.notify_all();
        });
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        // Wait until index build is complete (if one is in progress)
        {
            let mut b = self.building.lock();
            while *b {
                self.build_done.wait(&mut b);
            }
        }

        let inner = self.inner.read();
        let n = inner.ids.len();
        if n == 0 { return vec![]; }
        let top_k = top_k as usize;

        if let Some(ref ivf) = inner.ivf {
            search_ivf(&inner, ivf, vector, top_k)
        } else {
            search_brute(&inner, vector, top_k)
        }
    }
}

/// Build the IVF index from a data snapshot.
fn build_ivf(data_snap: Vec<f32>, n: usize, nc: usize) -> IvfIndex {
    // Build contiguous sample
    let sample_n = KMEANS_SAMPLE.min(n);
    let sample_step = n / sample_n;
    let mut sample_data: Vec<f32> = Vec::with_capacity(sample_n * DIM);
    for i in 0..sample_n {
        let di = i * sample_step;
        sample_data.extend_from_slice(&data_snap[di * DIM..(di + 1) * DIM]);
    }

    // Init centroids (evenly spaced from sample)
    let init_step = sample_n / nc;
    let mut centroids: Vec<f32> = Vec::with_capacity(nc * DIM);
    for ci in 0..nc {
        let si = ci * init_step;
        centroids.extend_from_slice(&sample_data[si * DIM..(si + 1) * DIM]);
    }

    // K-means iterations
    let mut sample_asgn = vec![0u32; sample_n];
    for _iter in 0..KMEANS_ITERS {
        let new_asgn: Vec<u32> = (0..sample_n)
            .into_par_iter()
            .map(|i| nearest_centroid(&centroids, &sample_data[i * DIM..(i + 1) * DIM]) as u32)
            .collect();
        if new_asgn == sample_asgn { break; }
        sample_asgn = new_asgn;

        let mut sums = vec![0.0f32; nc * DIM];
        let mut cnts = vec![0u32; nc];
        for i in 0..sample_n {
            let c = sample_asgn[i] as usize;
            let v = &sample_data[i * DIM..(i + 1) * DIM];
            let s = &mut sums[c * DIM..(c + 1) * DIM];
            for d in 0..DIM { s[d] += v[d]; }
            cnts[c] += 1;
        }
        for c in 0..nc {
            if cnts[c] > 0 {
                let cf = cnts[c] as f32;
                let cs = &mut centroids[c * DIM..(c + 1) * DIM];
                let ss = &sums[c * DIM..(c + 1) * DIM];
                for d in 0..DIM { cs[d] = ss[d] / cf; }
            }
        }
    }
    drop(sample_data);

    // Assign all vectors
    let all_asgn: Vec<u32> = (0..n)
        .into_par_iter()
        .map(|i| nearest_centroid(&centroids, &data_snap[i * DIM..(i + 1) * DIM]) as u32)
        .collect();
    drop(data_snap);

    // Build cells
    let mut cell_counts = vec![0u32; nc];
    for &a in &all_asgn { cell_counts[a as usize] += 1; }
    let mut cells: Vec<Vec<u32>> = cell_counts
        .iter()
        .map(|&cnt| Vec::with_capacity(cnt as usize))
        .collect();
    for (i, &a) in all_asgn.iter().enumerate() {
        cells[a as usize].push(i as u32);
    }

    IvfIndex { centroids, cells }
}

fn search_ivf(inner: &Inner, ivf: &IvfIndex, vector: &[f32], top_k: usize) -> Vec<SearchResult> {
    let probe = PROBE.min(NUM_CENTROIDS);
    let data = &inner.data;
    let ids = &inner.ids;

    let mut cdists: Vec<(f32, usize)> = (0..NUM_CENTROIDS)
        .map(|c| (l2_distance_f32(vector, ivf.centroid(c)), c))
        .collect();
    cdists.select_nth_unstable_by(probe - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
    cdists.truncate(probe);

    let total: usize = cdists.iter().map(|(_, c)| ivf.cells[*c].len()).sum();
    let mut results: Vec<(f32, u64)> = Vec::with_capacity(total);
    for (_, c) in &cdists {
        for &vi in &ivf.cells[*c] {
            let vi = vi as usize;
            let dist = l2_distance_f32(vector, &data[vi * DIM..(vi + 1) * DIM]);
            results.push((dist, ids[vi]));
        }
    }

    if results.len() > top_k {
        results.select_nth_unstable_by(top_k - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
        results.truncate(top_k);
    }
    results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
    results.into_iter().map(|(d, id)| SearchResult { id, distance: d as f64 }).collect()
}

fn search_brute(inner: &Inner, vector: &[f32], top_k: usize) -> Vec<SearchResult> {
    let n = inner.ids.len();
    let data = &inner.data;
    let ids = &inner.ids;
    let mut results: Vec<(f32, u64)> = (0..n)
        .into_par_iter()
        .map(|i| (l2_distance_f32(vector, &data[i * DIM..(i + 1) * DIM]), ids[i]))
        .collect();
    if results.len() > top_k {
        results.select_nth_unstable_by(top_k - 1, |a, b| a.0.partial_cmp(&b.0).unwrap());
        results.truncate(top_k);
    }
    results.sort_unstable_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
    results.into_iter().map(|(d, id)| SearchResult { id, distance: d as f64 }).collect()
}

#[inline(always)]
fn push_vector(data: &mut Vec<f32>, v: &[f32]) {
    if v.len() >= DIM {
        data.extend_from_slice(&v[..DIM]);
    } else {
        data.extend_from_slice(v);
        for _ in v.len()..DIM { data.push(0.0); }
    }
}

#[inline(always)]
fn nearest_centroid(centroids: &[f32], v: &[f32]) -> usize {
    let mut best = f32::MAX;
    let mut best_idx = 0usize;
    for c in 0..NUM_CENTROIDS {
        let d = l2_distance_f32(v, &centroids[c * DIM..(c + 1) * DIM]);
        if d < best { best = d; best_idx = c; }
    }
    best_idx
}

// SAFETY: VectorDB contains RwLock + Condvar which are Send+Sync.
// The raw pointer used in spawn is safe because VectorDB lives in an Arc.
