/// Thread-safe wrapper for passing *const VectorDB between threads.
/// SAFETY: VectorDB is Sync and lives in an Arc for the program lifetime.
struct RawSend(*const VectorDB);
unsafe impl Send for RawSend {}

pub struct VectorDB {
    inner: RwLock<Inner>,
    building: Mutex<bool>,
    build_done: Condvar,
}

