        {
            let mut inner = self.inner.write();
            inner.data.reserve(count * DIM);
            inner.ids.reserve(count);
            for (id, v) in &vectors {
                push_vector(&mut inner.data, v);
                inner.ids.push(*id);
            }
            inner.ivf = None;
        }

        // Build IVF index in background thread, return immediately
        {
            let mut b = self.building.lock();
            *b = true;
        }

        let raw = RawSend(self as *const VectorDB);
        std::thread::spawn(move || {
            let db: &VectorDB = unsafe { &*raw.0 };
